    private fun wouldCreateConsecutiveBlankLines(whiteSpaceElement: PsiWhiteSpace): Boolean {
        // Start from the whitespace element and look at what follows
        var currentElement = whiteSpaceElement.nextSibling
        var commentCount = 0

        // Count consecutive comments (especially KDoc comments)
        while (currentElement != null) {
            when (currentElement) {
                is PsiComment -> {
                    commentCount++
                }
                is PsiWhiteSpace -> {
                    // If we encounter whitespace with blank lines between comments, that's a sign
                    // that adding another blank line could create consecutive blank lines
                    val newlines = currentElement.text.count { it == '\n' }
                    if (commentCount > 0 && newlines > 1) {
                        return true
                    }
                    // Continue if it's just a single newline with indentation
                    if (newlines == 1) {
                        // Continue to next element
                    } else if (newlines > 1) {
                        // Multiple newlines might indicate existing blank lines
                        return commentCount > 1
                    }
                }
                else -> {
                    // We've reached a non-comment, non-whitespace element (likely annotation or declaration)
                    break
                }
            }
            currentElement = currentElement.nextSibling
        }

        // If we found multiple comments, adding a blank line might create consecutive blank lines
        return commentCount >= 2
    }"}

